use crate::error::{Result, TemplateFlowError};
use once_cell::sync::Lazy;
use std::env;
use std::path::PathBuf;
use std::time::Duration;

static DEFAULT_S3_ROOT: &str = "https://templateflow.s3.amazonaws.com";
static DEFAULT_TIMEOUT_SECS: u64 = 300; // 5 minutes

/// Configuration for TemplateFlow operations
///
/// This struct holds the configuration settings for TemplateFlow, including
/// cache directory location, S3 endpoints, and behavior options. Configuration
/// values are read from environment variables with sensible defaults.
///
/// # Environment Variables
/// - `TEMPLATEFLOW_HOME`: Cache directory (default: `~/.cache/templateflow`)
/// - `TEMPLATEFLOW_S3_ROOT`: S3 bucket URL (default: `https://templateflow.s3.amazonaws.com`)
/// - `TEMPLATEFLOW_AUTOUPDATE`: Auto-update skeleton index (default: `true`)
/// - `TEMPLATEFLOW_TIMEOUT`: HTTP timeout in seconds (default: `300`)
///
/// # Example
/// ```
/// use templateflow::Config;
///
/// let config = Config::new().unwrap();
/// println!("Cache directory: {:?}", config.home);
/// println!("S3 root: {}", config.s3_root);
/// ```
#[derive(Debug, Clone)]
pub struct Config {
    /// Local cache directory for templates
    pub home: PathBuf,

    /// S3 root URL for downloading templates
    pub s3_root: String,

    /// Whether to automatically update the skeleton index
    pub autoupdate: bool,

    /// Timeout for network operations
    pub timeout: Duration,
}

impl Config {
    /// Create a new Config with default values or from environment variables
    pub fn new() -> Result<Self> {
        let home = Self::get_home_dir()?;
        let s3_root = Self::get_s3_root();
        let autoupdate = Self::get_autoupdate();

