/// * `Ok(true)` if file was downloaded
/// * `Ok(false)` if file already exists with non-zero size
/// * `Err(_)` if download failed
pub async fn download_if_missing(s3_path: &str, local_path: &Path, show_progress: bool) -> Result<bool> {
    // Check if file exists and has non-zero size
    if local_path.exists() {
        let metadata = fs::metadata(local_path)?;
        if metadata.len() > 0 {
            return Ok(false);
        }
        // File exists but is empty, remove it
        fs::remove_file(local_path)?;
    }

    download_file(s3_path, local_path, show_progress).await?;
    Ok(true)
}

/// Get a file from S3, using cache if available
///
/// # Arguments
/// * `relative_path` - Path relative to templateflow home (e.g., "tpl-MNI152Lin/...")
///
/// # Returns
/// The local path to the file after ensuring it exists
pub async fn get(relative_path: &Path) -> Result<PathBuf> {
    let local_path = CONFIG.home.join(relative_path);

    // Convert to S3 path (relative to S3 root)
    let s3_path = relative_path.to_str()
        .ok_or_else(|| TemplateFlowError::ConfigError(
            "Invalid path: contains non-UTF8 characters".to_string()
        ))?;

    download_if_missing(s3_path, &local_path, true).await?;

    Ok(local_path)
}

/// Update the skeleton index file
///
/// Downloads the latest templateflow-skel.zip from GitHub and clears the layout cache
pub async fn update_skeleton() -> Result<()> {
    let skeleton_path = CONFIG.skeleton_path();
    let skeleton_url = "https://raw.githubusercontent.com/templateflow/python-client/master/templateflow/conf/templateflow-skel.zip";

    // Clear the layout cache before updating skeleton
    let cache = crate::layout_cache::LayoutCache::new();
    cache.clear()?;

    // Use download_file with full URL
    let client = reqwest::Client::new();
    let response = client
        .get(skeleton_url)
        .timeout(CONFIG.timeout)
        .send()
        .await
        .map_err(TemplateFlowError::DownloadError)?;

    // Check status
    if !response.status().is_success() {
        return Err(TemplateFlowError::DownloadError(
            reqwest::Error::from(response.error_for_status().unwrap_err())
        ));
    }

    // Get content length for progress bar
    let total_size = response.content_length().unwrap_or(0);

    // Create parent directory if needed
    if let Some(parent) = skeleton_path.parent() {
        std::fs::create_dir_all(parent)?;
    }

    // Create file
    let mut file = File::create(&skeleton_path)?;

    // Create progress bar
    let pb = ProgressBar::new(total_size);
    pb.set_style(
        ProgressStyle::default_bar()
            .template("{msg}\n{spinner:.green} [{elapsed_precise}] [{wide_bar:.cyan/blue}] {bytes}/{total_bytes} ({bytes_per_sec}, {eta})")
            .unwrap()
            .progress_chars("#>-"),
    );
    pb.set_message(format!("Downloading skeleton index"));

    // Stream the response body
    let mut downloaded: u64 = 0;
    let mut stream = response.bytes_stream();

    while let Some(chunk) = stream.next().await {
        let chunk = chunk.map_err(TemplateFlowError::DownloadError)?;
        file.write_all(&chunk)?;
        downloaded += chunk.len() as u64;
        pb.set_position(downloaded);
    }

    pb.finish_with_message("Skeleton index downloaded");

    Ok(())
}

/// Synchronous wrapper for update_skeleton
pub fn update_skeleton_sync() -> Result<()> {
    // Try to use existing runtime, or create new one if needed
    if let Ok(handle) = tokio::runtime::Handle::try_current() {
        // Check if we're in a multi-threaded runtime
        if std::thread::current().name().map_or(false, |name| name.contains("tokio-runtime-worker")) {
            tokio::task::block_in_place(|| {
                handle.block_on(update_skeleton())
            })
        } else {
            // Single-threaded runtime, spawn and wait
            let future = handle.spawn(update_skeleton());
            std::thread::sleep(std::time::Duration::from_millis(10)); // Brief yield
            futures::executor::block_on(future).map_err(|e| TemplateFlowError::CacheError(format!("Join error: {}", e)))?
        }
    } else {
        let rt = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
            .map_err(|e| TemplateFlowError::IoError(e.into()))?;

        rt.block_on(update_skeleton())
    }
}

