//! S3 download implementation
//!
//! This module handles downloading template files from the S3 bucket.

use crate::cache::Cache;
use crate::error::{Result, TemplateFlowError};
use crate::config::CONFIG;
use indicatif::{ProgressBar, ProgressStyle};
use reqwest::header::CONTENT_LENGTH;
use std::fs::{self, File};
use std::io::Write;
use std::path::{Path, PathBuf};
use tokio::io::AsyncWriteExt;
use futures_util::StreamExt;

/// Download a file from S3 to the local cache
///
/// # Arguments
/// * `s3_path` - Path relative to S3 root (e.g., "tpl-MNI152Lin/tpl-MNI152Lin_res-01_T1w.nii.gz")
/// * `local_path` - Local destination path
/// * `show_progress` - Whether to show a progress bar
///
/// # Example
/// ```rust,no_run
/// use templateflow::s3::download_file;
/// use std::path::Path;
///
/// # async fn example() -> Result<(), Box<dyn std::error::Error>> {
/// let local_path = Path::new("/tmp/template.nii.gz");
/// download_file("tpl-MNI152Lin/tpl-MNI152Lin_res-01_T1w.nii.gz", &local_path, true).await?;
/// # Ok(())
/// # }
/// ```
pub async fn download_file(s3_path: &str, local_path: &Path, show_progress: bool) -> Result<()> {
    // Construct full URL
    let url = format!("{}/{}", CONFIG.s3_root.trim_end_matches('/'), s3_path);

    // Create parent directory if it doesn't exist
    if let Some(parent) = local_path.parent() {
        fs::create_dir_all(parent)?;
    }

    // Create HTTP client with timeout
    let client = reqwest::Client::builder()
        .timeout(CONFIG.timeout)
        .build()
        .map_err(|e| TemplateFlowError::DownloadError(e))?;

    // Start the download
    let response = client
        .get(&url)
        .send()
        .await?;

    // Check if request was successful
    if !response.status().is_success() {
        return Err(TemplateFlowError::DownloadError(
            reqwest::Error::from(response.error_for_status().unwrap_err())
        ));
    }

    // Get content length for progress bar
    let total_size = response
        .headers()
        .get(CONTENT_LENGTH)
        .and_then(|ct_len| ct_len.to_str().ok())
        .and_then(|ct_len| ct_len.parse::<u64>().ok())
        .unwrap_or(0);

    // Create progress bar if requested
    let progress_bar = if show_progress && total_size > 0 {
        let pb = ProgressBar::new(total_size);
        pb.set_style(
            ProgressStyle::default_bar()
                .template("{spinner:.green} [{elapsed_precise}] [{bar:40.cyan/blue}] {bytes}/{total_bytes} ({eta})")
                .unwrap()
                .progress_chars("#>-"),
        );
        pb.set_message(format!("Downloading {}", s3_path));
        Some(pb)
    } else {
        None
    };

    // Create the file
    let mut file = tokio::fs::File::create(local_path).await?;

    // Download in chunks
    let mut downloaded = 0u64;
    let mut stream = response.bytes_stream();

    while let Some(chunk) = futures_util::StreamExt::next(&mut stream).await {
        let chunk = chunk?;
        file.write_all(&chunk).await?;

        downloaded += chunk.len() as u64;
        if let Some(ref pb) = progress_bar {
            pb.set_position(downloaded);
        }
    }

    // Finish progress bar
    if let Some(pb) = progress_bar {
        pb.finish_with_message("Download complete");
    }

    // Ensure all data is written
    file.flush().await?;

    // Verify file size if we know the expected size
    if total_size > 0 && downloaded != total_size {
        // Remove incomplete file
        let _ = tokio::fs::remove_file(local_path).await;
        return Err(TemplateFlowError::IoError(std::io::Error::new(
            std::io::ErrorKind::UnexpectedEof,
            format!("Downloaded {} bytes but expected {}", downloaded, total_size)
        )));
    }

    Ok(())
}

/// Synchronous wrapper for download_file
///
/// # Arguments
/// * `s3_path` - Path relative to S3 root
/// * `local_path` - Local destination path
/// * `show_progress` - Whether to show a progress bar
pub fn download_file_sync(s3_path: &str, local_path: &Path, show_progress: bool) -> Result<()> {
    // Try to use existing runtime, or create new one if needed
    if let Ok(handle) = tokio::runtime::Handle::try_current() {
        tokio::task::block_in_place(|| {
            handle.block_on(download_file(s3_path, local_path, show_progress))
        })
    } else {
        let rt = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
            .map_err(|e| TemplateFlowError::IoError(
                std::io::Error::new(std::io::ErrorKind::Other, e)
            ))?;

        rt.block_on(download_file(s3_path, local_path, show_progress))
    }
}

