//! Comprehensive integration tests for the TemplateFlow API
//!
//! These tests require network connectivity and will download real data.
//! They are marked with #[ignore] by default to avoid running in CI.

use templateflow::{get_metadata, get_citations, templates, ls, get, get_async, get_multiple_async};
use std::collections::HashMap;
use tempfile::TempDir;

/// Helper to set up a temporary home directory for testing
fn setup_test_environment() -> TempDir {
    let temp_dir = TempDir::new().expect("Failed to create temp dir");
    std::env::set_var("TEMPLATEFLOW_HOME", temp_dir.path());
    temp_dir
}

#[test]
#[ignore] // Requires network access
fn test_templates_basic() {
    let _temp_dir = setup_test_environment();

    // Test listing all templates
    let all_templates = templates(None).expect("Failed to list templates");
    assert!(!all_templates.is_empty(), "Should have at least one template");

    // Verify some known templates exist
    assert!(all_templates.contains(&"MNI152NLin2009cAsym".to_string()));
    assert!(all_templates.contains(&"MNI152Lin".to_string()));
    assert!(all_templates.contains(&"fsaverage".to_string()));

    println!("Found {} templates", all_templates.len());
}

#[test]
#[ignore] // Requires network access
fn test_templates_with_query() {
    let _temp_dir = setup_test_environment();

    // Test filtering templates by resolution
    let mut query = HashMap::new();
    query.insert("res".to_string(), "01".to_string());

    let filtered_templates = templates(Some(&query)).expect("Failed to query templates");
    assert!(!filtered_templates.is_empty(), "Should have templates with res=01");

    // All returned templates should have files with res=01
    for template in &filtered_templates {
        let mut template_query = HashMap::new();
        template_query.insert("res".to_string(), "01".to_string());
        let files = ls(template, Some(&template_query)).expect("Failed to list files");
        assert!(!files.is_empty(), "Template {} should have files with res=01", template);
    }
}

#[test]
#[ignore] // Requires network access
fn test_ls_basic() {
    let _temp_dir = setup_test_environment();

    // Test listing all files for a well-known template
    let files = ls("MNI152NLin2009cAsym", None).expect("Failed to list files");
    assert!(!files.is_empty(), "MNI152NLin2009cAsym should have files");

    // Verify file paths are properly formatted
    for file in &files {
        let path_str = file.to_string_lossy();
        assert!(path_str.starts_with("tpl-MNI152NLin2009cAsym/"));
        assert!(path_str.contains("tpl-MNI152NLin2009cAsym"));
    }
}

#[test]
#[ignore] // Requires network access
fn test_ls_with_queries() {
    let _temp_dir = setup_test_environment();

    // Test various query combinations
    let test_cases = vec![
        // Single entity queries
        (vec![("suffix", "T1w")], "suffix=T1w"),
        (vec![("res", "01")], "res=01"),
        (vec![("desc", "brain")], "desc=brain"),

        // Multiple entity queries
        (vec![("res", "01"), ("suffix", "T1w")], "res=01,suffix=T1w"),
        (vec![("suffix", "mask"), ("desc", "brain")], "suffix=mask,desc=brain"),
    ];

    for (query_params, description) in test_cases {
        let mut query = HashMap::new();
        for (key, value) in query_params {
            query.insert(key.to_string(), value.to_string());
        }

