//! Advanced integration tests for TemplateFlow
//!
//! These tests cover more complex scenarios, edge cases, and stress testing.

use templateflow::{ls, get, get_multiple_async, templates};
use std::collections::HashMap;
use tempfile::TempDir;
use std::sync::Arc;
use std::sync::atomic::AtomicUsize;

fn setup_test_environment() -> TempDir {
    let temp_dir = TempDir::new().expect("Failed to create temp dir");
    std::env::set_var("TEMPLATEFLOW_HOME", temp_dir.path());
    temp_dir
}

#[test]
#[ignore] // Requires network access
fn test_all_templates_have_files() {
    let _temp_dir = setup_test_environment();

    // Get all templates
    let all_templates = templates(None).expect("Failed to list templates");

    let mut templates_without_files = Vec::new();
    let mut total_file_count = 0;

    // Check each template has at least one file
    for template in &all_templates {
        match ls(template, None) {
            Ok(files) => {
                if files.is_empty() {
                    templates_without_files.push(template.clone());
                } else {
                    total_file_count += files.len();
                }
            }
            Err(_) => {
                templates_without_files.push(template.clone());
            }
        }
    }

    println!("Total templates: {}", all_templates.len());
    println!("Total files across all templates: {}", total_file_count);

    if !templates_without_files.is_empty() {
        println!("Warning: Templates without files: {:?}", templates_without_files);
    }

    // Most templates should have files
    assert!(templates_without_files.len() < all_templates.len() / 2,
            "Too many templates without files");
}

#[test]
#[ignore] // Requires network access
fn test_complex_queries() {
    let _temp_dir = setup_test_environment();

    // Test complex query combinations on MNI template
    let template = "MNI152NLin2009cAsym";

    // Get all files first to understand what's available
    let all_files = ls(template, None).expect("Failed to list all files");
    println!("Template {} has {} total files", template, all_files.len());

    // Test increasingly specific queries
    let query_combinations = vec![
        vec![("suffix", "T1w")],
        vec![("suffix", "mask")],
        vec![("suffix", "T1w"), ("res", "01")],
        vec![("suffix", "mask"), ("desc", "brain")],
        vec![("suffix", "T2w"), ("res", "01")],
        vec![("ext", ".nii.gz")],
        vec![("ext", ".json")],
    ];

    let mut query_results = HashMap::new();

    for query_params in query_combinations {
        let mut query = HashMap::new();
        let mut query_str = String::new();

        for (i, (key, value)) in query_params.iter().enumerate() {
            query.insert(key.to_string(), value.to_string());
            if i > 0 {
                query_str.push(',');
            }
            query_str.push_str(&format!("{}={}", key, value));
        }

        match ls(template, Some(&query)) {
            Ok(files) => {
                println!("Query [{}] returned {} files", query_str, files.len());
                query_results.insert(query_str, files.len());

                // Verify each file actually matches the query
                for file in &files {
                    let path_str = file.to_string_lossy();

                    if query.contains_key("suffix") {
                        let suffix = query.get("suffix").unwrap();
                        assert!(path_str.contains(&format!("_{}", suffix)),
                                "File {} should contain suffix {}", path_str, suffix);
                    }

                    if query.contains_key("res") {
                        let res = query.get("res").unwrap();
                        assert!(path_str.contains(&format!("res-{}", res)),
                                "File {} should contain resolution {}", path_str, res);
                    }

                    if query.contains_key("ext") {
                        let ext = query.get("ext").unwrap();
                        assert!(path_str.ends_with(ext),
                                "File {} should end with extension {}", path_str, ext);
                    }
                }
            }
            Err(_) => {
                println!("Query [{}] returned no matches", query_str);
                query_results.insert(query_str, 0);
            }
        }
    }

    // Verify that more specific queries return fewer results
    let t1w_count = query_results.get("suffix=T1w").unwrap_or(&0);
    let t1w_res01_count = query_results.get("suffix=T1w,res=01").unwrap_or(&0);

    if *t1w_count > 0 && *t1w_res01_count > 0 {
        assert!(t1w_res01_count <= t1w_count,
                "More specific query should return fewer or equal results");
    }
}

