#[ignore] // Requires network access and downloads files
async fn test_parallel_download_performance() {
    let _temp_dir = setup_test_environment();

    // Find files to download for performance testing - use a more specific query to get fewer files
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "mask".to_string());
    query.insert("res".to_string(), "02".to_string());
    query.insert("desc".to_string(), "brain".to_string());

    match ls("MNI152NLin2009cAsym", Some(&query)) {
        Ok(files) => {
            if files.len() >= 1 {
                println!("Testing parallel download with {} files", files.len());

                // Measure sequential download time
                let start_seq = std::time::Instant::now();
                let _seq_results = get("MNI152NLin2009cAsym", Some(&query))
                    .expect("Sequential download failed");
                let seq_duration = start_seq.elapsed();

                // Clear cache for fair comparison
                let cache_dir = std::env::var("TEMPLATEFLOW_HOME").unwrap();
                std::fs::remove_dir_all(&cache_dir).ok();
                std::fs::create_dir_all(&cache_dir).ok();

                // Measure parallel download time
                let start_par = std::time::Instant::now();
                let _par_results = get_multiple_async("MNI152NLin2009cAsym", Some(&query)).await
                    .expect("Parallel download failed");
                let par_duration = start_par.elapsed();

                println!("Sequential download: {:?}", seq_duration);
                println!("Parallel download: {:?}", par_duration);

                // Parallel should be faster for multiple files
                // (or at least not significantly slower)
                assert!(par_duration.as_secs_f64() <= seq_duration.as_secs_f64() * 1.5,
                        "Parallel download should not be much slower than sequential");
            } else {
                println!("Not enough files for performance test");
            }
        }
        Err(_) => {
            println!("Could not find files for performance test");
        }
    }
}

