}

#[test]
#[ignore] // Requires network access
fn test_ls_with_queries() {
    let _temp_dir = setup_test_environment();

    // Test various query combinations
    let test_cases = vec![
        // Single entity queries
        (vec![("suffix", "T1w")], "suffix=T1w"),
        (vec![("res", "01")], "res=01"),
        (vec![("desc", "brain")], "desc=brain"),

        // Multiple entity queries
        (vec![("res", "01"), ("suffix", "T1w")], "res=01,suffix=T1w"),
        (vec![("suffix", "mask"), ("desc", "brain")], "suffix=mask,desc=brain"),
    ];

    for (query_params, description) in test_cases {
        let mut query = HashMap::new();
        for (key, value) in query_params {
            query.insert(key.to_string(), value.to_string());
        }

        match ls("MNI152NLin2009cAsym", Some(&query)) {
            Ok(files) => {
                println!("Query {} returned {} files", description, files.len());
                // Verify that returned files match the query
                for file in &files {
                    let path_str = file.to_string_lossy();
                    for (key, value) in &query {
                        if key == "suffix" {
                            assert!(path_str.contains(&format!("_{}.nii", value)) || 
                                    path_str.contains(&format!("_{}.json", value)),
                                    "File {} should match suffix={}", path_str, value);
                        } else if key == "res" {
                            assert!(path_str.contains(&format!("_res-{}", value)),
                                    "File {} should match res={}", path_str, value);
                        } else if key == "desc" {
                            assert!(path_str.contains(&format!("_desc-{}", value)),
                                    "File {} should match desc={}", path_str, value);
                        }
                    }
                }
            }
            Err(_) => {
                println!("Query {} returned no matches (this is OK)", description);
            }
        }
    }
}

