            }
        }
        Err(_) => {
            println!("No files matched the test query for async test");
        }
    }
}

#[tokio::test]
#[ignore] // Requires network access
async fn test_get_multiple_async() {
    let _temp_dir = setup_test_environment();

    // Test concurrent downloads of multiple files
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "mask".to_string());

    match ls("MNI152NLin2009cAsym", Some(&query)) {
        Ok(available_files) => {
            if available_files.len() > 1 {
                let start = std::time::Instant::now();
                let downloaded = get_multiple_async("MNI152NLin2009cAsym", Some(&query)).await
                    .expect("Failed to download files concurrently");
                let duration = start.elapsed();

                println!("Downloaded {} files concurrently in {:?}", downloaded.len(), duration);

                assert_eq!(downloaded.len(), available_files.len(), 
                           "Should download all matching files");

                for file in &downloaded {
                    assert!(file.exists(), "Downloaded file should exist: {:?}", file);
                }
            } else {
                println!("Not enough files for concurrent download test");
            }
        }
        Err(_) => {
            println!("No files matched the test query for concurrent download test");
        }
    }
}

#[test]
#[ignore] // Requires network access
fn test_error_handling() {
    let _temp_dir = setup_test_environment();

    // Test various error conditions

    // Non-existent template
    assert!(ls("NonExistentTemplate", None).is_err());
    assert!(get("NonExistentTemplate", None).is_err());
    assert!(get_metadata("NonExistentTemplate").is_err());

    // Query with no matches
    let mut impossible_query = HashMap::new();
    impossible_query.insert("res".to_string(), "999".to_string());
    impossible_query.insert("suffix".to_string(), "NonExistentSuffix".to_string());

    assert!(ls("MNI152NLin2009cAsym", Some(&impossible_query)).is_err());
    assert!(get("MNI152NLin2009cAsym", Some(&impossible_query)).is_err());
}

#[test]
#[ignore] // Requires network access
fn test_cache_behavior() {
    let temp_dir = setup_test_environment();

    // Download a file
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "T1w".to_string());
    query.insert("res".to_string(), "02".to_string());

    if let Ok(files) = ls("MNI152NLin2009cAsym", Some(&query)) {
        if !files.is_empty() {
            // First download
            let downloaded1 = get("MNI152NLin2009cAsym", Some(&query))
                .expect("Failed to download files");

            // Verify files are in cache
            for file in &downloaded1 {
                assert!(file.exists());
                assert!(file.starts_with(temp_dir.path()));
            }

            // Delete one file to test re-download
            std::fs::remove_file(&downloaded1[0]).expect("Failed to remove file");
            assert!(!downloaded1[0].exists());

            // Re-download should restore the file
            let downloaded2 = get("MNI152NLin2009cAsym", Some(&query))
                .expect("Failed to re-download files");

            assert_eq!(downloaded1.len(), downloaded2.len());
            assert!(downloaded2[0].exists(), "File should be re-downloaded");
        }
    }
}

