//! Core API functions for TemplateFlow
//!
//! This module implements the main public API functions:
//! - `ls`: List files for a template with BIDS queries
//! - `get`: Download and return file paths
//! - `templates`: List available templates
//! - `get_metadata`: Get template metadata
//! - `get_citations`: Get template citations

use crate::bids::{TemplateLayout, TemplateMetadata};
use crate::config::CONFIG;
use crate::error::{Result, TemplateFlowError};
use crate::layout_cache::LayoutCache;
use crate::s3;
use once_cell::sync::Lazy;
use std::collections::HashMap;
use std::path::PathBuf;
use std::sync::{Arc, Mutex};

/// Global template layout instance
static LAYOUT: Lazy<Arc<Mutex<Option<TemplateLayout>>>> = Lazy::new(|| Arc::new(Mutex::new(None)));

/// Global layout cache instance
static LAYOUT_CACHE: Lazy<LayoutCache> = Lazy::new(|| LayoutCache::new());

/// Ensure the layout is loaded (with caching)
fn ensure_layout() -> Result<()> {
    let mut layout_guard = LAYOUT.lock().unwrap();

    if layout_guard.is_none() {
        // Try to load from cache first
        if let Some(cached_layout) = LAYOUT_CACHE.load()? {
            *layout_guard = Some(cached_layout);
            return Ok(());
        }

        // Download skeleton if needed
        let skeleton_path = CONFIG.skeleton_path();
        if !skeleton_path.exists() {
            s3::update_skeleton_sync()?;
        }

        // Load the layout from skeleton
        let layout = crate::bids::load_skeleton_from_file(&skeleton_path)?;

        // Save to cache for next time
        LAYOUT_CACHE.save(&layout)?;

        *layout_guard = Some(layout);
    }

    Ok(())
}

/// Get template metadata
///
/// Retrieves metadata for a specific brain template including name, description,
/// authors, license, and references. The metadata is first checked in the skeleton
/// cache, and if not found, downloaded from S3.
///
/// # Arguments
/// * `template` - Template identifier (e.g., "MNI152Lin", "MNI152NLin2009cAsym")
///
/// # Returns
/// * `Result<TemplateMetadata>` - The template metadata containing:
///   - `name`: Template display name
///   - `description`: Optional template description
///   - `authors`: List of template authors
///   - `license`: Optional license information
///   - `references_and_links`: Related publications and resources
///
/// # Errors
/// Returns `TemplateFlowError::TemplateNotFound` if the template doesn't exist
/// or `TemplateFlowError::DownloadError` if network issues occur.
///
/// # Example
/// ```no_run
/// use templateflow::api::get_metadata;
/// 
/// let metadata = get_metadata("MNI152Lin").unwrap();
/// println!("Template name: {}", metadata.name);
/// println!("Authors: {:?}", metadata.authors);
/// if let Some(license) = &metadata.license {
///     println!("License: {}", license);
/// }
/// ```
pub fn get_metadata(template: &str) -> Result<TemplateMetadata> {
    ensure_layout()?;

    let layout_guard = LAYOUT.lock().unwrap();
    let layout = layout_guard.as_ref().unwrap();

    // First check if metadata exists in the skeleton
    if let Some(metadata) = layout.get_metadata(template) {
        return Ok(metadata.clone());
    }

    // If not in skeleton, try to download template_description.json
    let template_dir = CONFIG.home.join(format!("tpl-{}", template));
    let metadata_path = template_dir.join("template_description.json");

    // Download if not cached
    if !metadata_path.exists() {
        let s3_path = format!("tpl-{}/template_description.json", template);
        s3::download_file_sync(&s3_path, &metadata_path, false)?;
    }

    // Parse the metadata
    TemplateMetadata::from_file(&metadata_path)
}

/// Get template citations
///
/// Retrieves citation information for a specific brain template. Citations can be
/// returned as raw references or formatted as BibTeX entries for easy inclusion
/// in scientific manuscripts.
///
/// # Arguments
/// * `template` - Template identifier (e.g., "MNI152Lin", "MNI152NLin2009cAsym")
/// * `bibtex` - If true, format citations as BibTeX entries; if false, return raw references
///
/// # Returns
/// * `Result<Vec<String>>` - List of citations formatted according to the `bibtex` parameter
///
/// # Errors
/// Returns `TemplateFlowError::TemplateNotFound` if the template doesn't exist.
///
/// # Example
/// ```no_run
/// use templateflow::api::get_citations;
/// 
/// // Get raw citations
/// let citations = get_citations("MNI152Lin", false).unwrap();
/// for citation in &citations {
///     println!("Reference: {}", citation);
/// }
/// 
/// // Get BibTeX-formatted citations
/// let bibtex_citations = get_citations("MNI152Lin", true).unwrap();
/// for entry in &bibtex_citations {
///     println!("{}", entry);
/// }
/// ```
pub fn get_citations(template: &str, bibtex: bool) -> Result<Vec<String>> {
    let metadata = get_metadata(template)?;

    let citations: Vec<String> = if bibtex {
        // TODO: Implement BibTeX formatting
        metadata.references_and_links
            .iter()
            .enumerate()
            .map(|(idx, ref_val)| {
                format!(
                    "@misc{{{}{},\n  title = {{{}}},\n  note = {{{}}}\n}}",
                    template,
                    idx + 1,
                    metadata.name,
                    serde_json::to_string(ref_val).unwrap_or_default()
                )
            })
            .collect()
    } else {
        metadata.references_and_links
            .iter()
            .map(|v| serde_json::to_string_pretty(v).unwrap_or_default())
            .collect()
    };

    Ok(citations)
}

/// List available templates
///
/// Returns a list of all available brain templates in the TemplateFlow repository.
/// Can optionally filter templates based on BIDS entities (e.g., templates that
/// have files with specific resolution or suffix).
///
/// # Arguments
/// * `query` - Optional query parameters as key-value pairs to filter templates.
///   Common query keys include:
///   - `"res"` or `"resolution"`: Spatial resolution (e.g., "01", "02")
///   - `"suffix"`: File type suffix (e.g., "T1w", "mask", "brain")
///   - `"atlas"`: Atlas name (e.g., "AAL", "Schaefer2018")
///   - `"desc"` or `"description"`: Description label
///
/// # Returns
/// * `Result<Vec<String>>` - Sorted list of template identifiers
///
/// # Example
/// ```no_run
/// use templateflow::api::templates;
/// use std::collections::HashMap;
/// 
/// // Get all available templates
/// let all_templates = templates(None).unwrap();
/// println!("Found {} templates", all_templates.len());
/// 
/// // Get templates that have 1mm resolution files
/// let mut query = HashMap::new();
/// query.insert("res".to_string(), "01".to_string());
/// let high_res_templates = templates(Some(&query)).unwrap();
/// 
/// // Get templates with T1-weighted images
/// let mut query = HashMap::new();
/// query.insert("suffix".to_string(), "T1w".to_string());
/// let t1w_templates = templates(Some(&query)).unwrap();
/// ```
pub fn templates(query: Option<&HashMap<String, String>>) -> Result<Vec<String>> {
    ensure_layout()?;

    let layout_guard = LAYOUT.lock().unwrap();
    let layout = layout_guard.as_ref().unwrap();

    if let Some(query_params) = query {
        // Get all files matching the query
        let files = layout.query(query_params);

        // Extract unique template names
        let mut template_set = std::collections::HashSet::new();
        for file in files {
            template_set.insert(file.template.clone());
        }

        let mut templates: Vec<String> = template_set.into_iter().collect();
        templates.sort();
        Ok(templates)
    } else {
        // Return all templates
        let mut templates: Vec<String> = layout.get_templates()
            .into_iter()
            .map(|s| s.to_string())
            .collect();
        templates.sort();
        Ok(templates)
    }
}

/// List files for a template with BIDS queries
///
/// Returns a list of file paths available for a specific template, optionally
/// filtered by BIDS entities. This function does not download files, it only
/// lists what's available in the repository.
///
/// # Arguments
/// * `template` - Template identifier (e.g., "MNI152Lin", "MNI152NLin2009cAsym")
/// * `query` - Optional query parameters as key-value pairs to filter files.
///   Common query keys include:
///   - `"res"` or `"resolution"`: Spatial resolution (e.g., "01", "02")
///   - `"suffix"`: File type (e.g., "T1w", "mask", "brain", "probseg")
///   - `"atlas"`: Atlas name (e.g., "AAL", "Schaefer2018")
///   - `"hemi"` or `"hemisphere"`: Hemisphere ("L" or "R")
///   - `"desc"` or `"description"`: Description label
///   - `"ext"` or `"extension"`: File extension (e.g., ".nii.gz", ".gii")
///
/// # Returns
/// * `Result<Vec<PathBuf>>` - List of relative file paths matching the query
///
/// # Errors
/// Returns `TemplateFlowError::NoFilesMatched` if no files match the query.
///
/// # Example
/// ```no_run
/// use templateflow::api::ls;
/// use std::collections::HashMap;
/// 
/// // List all files for a template
/// let all_files = ls("MNI152Lin", None).unwrap();
/// println!("Template has {} files", all_files.len());
/// 
/// // List only 1mm resolution T1-weighted images
/// let mut query = HashMap::new();
/// query.insert("res".to_string(), "01".to_string());
/// query.insert("suffix".to_string(), "T1w".to_string());
/// let t1w_files = ls("MNI152Lin", Some(&query)).unwrap();
/// 
/// // List brain masks at any resolution
/// let mut query = HashMap::new();
/// query.insert("suffix".to_string(), "mask".to_string());
/// let mask_files = ls("MNI152Lin", Some(&query)).unwrap();
/// ```
pub fn ls(template: &str, query: Option<&HashMap<String, String>>) -> Result<Vec<PathBuf>> {
    ensure_layout()?;

    let layout_guard = LAYOUT.lock().unwrap();
    let layout = layout_guard.as_ref().unwrap();

    // Build query with template
    let mut full_query = HashMap::new();
    full_query.insert("tpl".to_string(), template.to_string());

    // Add additional query parameters if provided
    if let Some(params) = query {
        for (key, value) in params {
            full_query.insert(key.clone(), value.clone());
        }
    }

    // Query the layout
    let files = layout.query(&full_query);

    if files.is_empty() {
        return Err(TemplateFlowError::NoFilesMatched);
    }

    // Convert to paths
    let paths: Vec<PathBuf> = files.into_iter()
        .map(|f| f.path.clone())
        .collect();

    Ok(paths)
}

/// Download and return file paths for a template
///
/// Downloads template files from S3 to the local cache and returns their paths.
/// Files are cached locally, so subsequent calls will return immediately without
/// re-downloading. The local cache is located at `~/.cache/templateflow` by default.
///
/// # Arguments
/// * `template` - Template identifier (e.g., "MNI152Lin", "MNI152NLin2009cAsym")
/// * `query` - Optional query parameters as key-value pairs to filter files.
///   See [`ls`] for available query keys.
///
/// # Returns
/// * `Result<Vec<PathBuf>>` - List of absolute paths to downloaded files in the local cache
///
/// # Errors
/// - Returns `TemplateFlowError::NoFilesMatched` if no files match the query
/// - Returns `TemplateFlowError::DownloadError` if network issues occur
/// - Returns `TemplateFlowError::IoError` if file system operations fail
///
/// # Example
/// ```no_run
/// use templateflow::api::get;
/// use std::collections::HashMap;
/// 
/// // Download all files for a template (may be many files!)
/// let all_files = get("MNI152Lin", None).unwrap();
/// println!("Downloaded {} files", all_files.len());
/// 
/// // Download only the 1mm T1-weighted image
/// let mut query = HashMap::new();
/// query.insert("res".to_string(), "01".to_string());
/// query.insert("suffix".to_string(), "T1w".to_string());
/// let t1w_files = get("MNI152Lin", Some(&query)).unwrap();
/// 
/// // Files are cached, so this returns immediately
/// let cached_files = get("MNI152Lin", Some(&query)).unwrap();
/// assert_eq!(t1w_files, cached_files);
/// ```
pub fn get(template: &str, query: Option<&HashMap<String, String>>) -> Result<Vec<PathBuf>> {
    // First list the files
    let files = ls(template, query)?;

    // Download each file
    let mut downloaded_paths = Vec::new();

    for file_path in files {
        // Construct local path
        let local_path = CONFIG.home.join(&file_path);

        // Skip if already exists
        if local_path.exists() {
            downloaded_paths.push(local_path);
            continue;
        }

        // Download the file using the path relative to S3 root
        s3::download_file_sync(&file_path.to_string_lossy(), &local_path, true)?;
        downloaded_paths.push(local_path);
    }

    Ok(downloaded_paths)
}

/// Asynchronously download and return file paths for a template
///
/// Async version of [`get`]. Downloads template files from S3 to the local cache
/// asynchronously. Files are downloaded sequentially but without blocking the
/// thread. For concurrent downloads of multiple files, use [`get_multiple_async`].
///
/// # Arguments
/// * `template` - Template identifier (e.g., "MNI152Lin", "MNI152NLin2009cAsym")
/// * `query` - Optional query parameters as key-value pairs to filter files.
///   See [`ls`] for available query keys.
///
/// # Returns
/// * `Result<Vec<PathBuf>>` - List of absolute paths to downloaded files in the local cache
///
/// # Errors
/// - Returns `TemplateFlowError::NoFilesMatched` if no files match the query
/// - Returns `TemplateFlowError::DownloadError` if network issues occur
/// - Returns `TemplateFlowError::IoError` if file system operations fail
///
/// # Example
/// ```no_run
/// use templateflow::api::get_async;
/// use std::collections::HashMap;
/// 
/// # async fn example() -> Result<(), Box<dyn std::error::Error>> {
/// // Download all files for a template asynchronously
/// let all_files = get_async("MNI152Lin", None).await?;
/// println!("Downloaded {} files", all_files.len());
/// 
/// // Download specific files with query
/// let mut query = HashMap::new();
/// query.insert("res".to_string(), "01".to_string());
/// query.insert("suffix".to_string(), "T1w".to_string());
/// let t1w_files = get_async("MNI152Lin", Some(&query)).await?;
/// 
/// // Use in async context with other async operations
/// let (template_files, other_data) = tokio::join!(
///     get_async("MNI152Lin", Some(&query)),
///     other_async_operation()
/// );
/// # Ok(())
/// # }
/// # async fn other_async_operation() -> Result<(), Box<dyn std::error::Error>> { Ok(()) }
/// ```
pub async fn get_async(template: &str, query: Option<&HashMap<String, String>>) -> Result<Vec<PathBuf>> {
    // First list the files
    let files = ls(template, query)?;

    // Download each file
    let mut downloaded_paths = Vec::new();

    for file_path in files {
        // Construct local path
        let local_path = CONFIG.home.join(&file_path);

        // Skip if already exists
        if local_path.exists() {
            downloaded_paths.push(local_path);
            continue;
        }

        // Download the file using the path relative to S3 root
        s3::download_file(&file_path.to_string_lossy(), &local_path, true).await?;
        downloaded_paths.push(local_path);
    }

    Ok(downloaded_paths)
}

/// Asynchronously download multiple files concurrently
///
/// Downloads multiple template files in parallel for improved performance when
/// fetching many files. This function is particularly useful when downloading
/// entire templates or large sets of files, as it can significantly reduce
/// total download time compared to sequential downloads.
///
/// Files that are already cached are returned immediately without re-downloading.
/// Only missing files are downloaded concurrently.
///
/// # Arguments
/// * `template` - Template identifier (e.g., "MNI152Lin", "MNI152NLin2009cAsym")
/// * `query` - Optional query parameters as key-value pairs to filter files.
///   See [`ls`] for available query keys.
///
/// # Returns
/// * `Result<Vec<PathBuf>>` - List of absolute paths to downloaded files in the local cache
///
/// # Errors
/// - Returns `TemplateFlowError::NoFilesMatched` if no files match the query
/// - Returns `TemplateFlowError::DownloadError` if any download fails
/// - Returns `TemplateFlowError::IoError` if file system operations fail
///
/// # Example
/// ```no_run
/// use templateflow::api::get_multiple_async;
/// use std::collections::HashMap;
/// 
/// # async fn example() -> Result<(), Box<dyn std::error::Error>> {
/// // Download all atlas files concurrently
/// let mut query = HashMap::new();
/// query.insert("atlas".to_string(), "AAL".to_string());
/// let atlas_files = get_multiple_async("MNI152NLin2009cAsym", Some(&query)).await?;
/// println!("Downloaded {} atlas files in parallel", atlas_files.len());
/// 
/// // Download all files at a specific resolution
/// let mut query = HashMap::new();
/// query.insert("res".to_string(), "01".to_string());
/// let high_res_files = get_multiple_async("MNI152Lin", Some(&query)).await?;
/// 
/// // Measure performance improvement
/// use std::time::Instant;
/// let start = Instant::now();
/// let files = get_multiple_async("OASIS30ANTs", None).await?;
/// println!("Downloaded {} files in {:?}", files.len(), start.elapsed());
/// # Ok(())
/// # }
/// ```
pub async fn get_multiple_async(template: &str, query: Option<&HashMap<String, String>>) -> Result<Vec<PathBuf>> {
    use futures::future::join_all;

    // First list the files
    let files = ls(template, query)?;

    // Prepare download tasks
    let mut download_tasks = Vec::new();
    let mut already_cached = Vec::new();

    for file_path in files {
        // Construct local path
        let local_path = CONFIG.home.join(&file_path);

        // Skip if already exists
        if local_path.exists() {
            already_cached.push(local_path);
            continue;
        }

        // Create download task
        let s3_path = file_path.to_string_lossy().to_string();
        let local_path_clone = local_path.clone();
        let download_task = async move {
            s3::download_file(&s3_path, &local_path_clone, true).await?;
            Ok::<PathBuf, TemplateFlowError>(local_path_clone)
        };

        download_tasks.push(download_task);
    }

    // Execute all downloads concurrently
    let download_results = join_all(download_tasks).await;

    // Collect results
    let mut downloaded_paths = already_cached;
    for result in download_results {
        downloaded_paths.push(result?);
    }

    Ok(downloaded_paths)
}

/// Asynchronously download multiple files concurrently with advanced options
///
/// Downloads multiple template files with configurable concurrency limits,
/// retry logic, and detailed progress reporting. This function provides fine-grained
/// control over the download process for optimal performance and reliability.
///
/// # Arguments
/// * `template` - Template identifier (e.g., "MNI152Lin", "MNI152NLin2009cAsym")
/// * `query` - Optional query parameters as key-value pairs to filter files
/// * `options` - Download options for concurrency, retries, and progress
///
/// # Returns
/// * `Result<Vec<PathBuf>>` - List of absolute paths to downloaded files
///
/// # Example
/// ```no_run
/// use templateflow::api::{get_multiple_async_advanced, ParallelDownloadOptions};
/// use std::collections::HashMap;
/// 
/// # async fn example() -> Result<(), Box<dyn std::error::Error>> {
/// let options = ParallelDownloadOptions {
///     max_concurrent: 5,
///     max_retries: 3,
///     show_progress: true,
/// };
/// 
/// let mut query = HashMap::new();
/// query.insert("res".to_string(), "01".to_string());
/// let files = get_multiple_async_advanced("MNI152Lin", Some(&query), options).await?;
/// # Ok(())
/// # }
/// ```
pub async fn get_multiple_async_advanced(
    template: &str, 
    query: Option<&HashMap<String, String>>,
    options: ParallelDownloadOptions,
) -> Result<Vec<PathBuf>> {
    use futures::stream::{self, StreamExt};
    use indicatif::{MultiProgress, ProgressBar, ProgressStyle};

    // First list the files
    let files = ls(template, query)?;

    // Separate cached and pending downloads
    let mut already_cached = Vec::new();
    let mut pending_downloads = Vec::new();

    for file_path in files {
        let local_path = CONFIG.home.join(&file_path);

        if local_path.exists() {
            already_cached.push(local_path);
        } else {
            pending_downloads.push((file_path, local_path));
        }
    }

    if pending_downloads.is_empty() {
        return Ok(already_cached);
    }

    let num_downloads = pending_downloads.len();

    // Create multi-progress if requested
    let multi_progress = if options.show_progress {
        Some(MultiProgress::new())
    } else {
        None
    };

    // Create overall progress bar
    let overall_pb = if let Some(ref mp) = multi_progress {
        let pb = mp.add(ProgressBar::new(num_downloads as u64));
        pb.set_style(
            ProgressStyle::default_bar()
                .template("[{elapsed_precise}] {bar:40.cyan/blue} {pos}/{len} files")
                .unwrap()
                .progress_chars("##-"),
        );
        pb.set_message(format!("Downloading {} files", num_downloads));
        Some(pb)
    } else {
        None
    };

    // Create download stream with concurrency limit
    let download_stream = stream::iter(pending_downloads)
        .map(|(file_path, local_path)| {
            let s3_path = file_path.to_string_lossy().to_string();
            let mp_clone = multi_progress.clone();
            let overall_pb_clone = overall_pb.clone();

            async move {
                // Retry logic
                let mut attempts = 0;
                loop {
                    attempts += 1;

                    // Show individual progress only if not using multi-progress
                    let show_individual_progress = mp_clone.is_none() && options.show_progress;

                    match s3::download_file(&s3_path, &local_path, show_individual_progress).await {
                        Ok(_) => {
                            if let Some(ref pb) = overall_pb_clone {
                                pb.inc(1);
                            }
                            return Ok::<PathBuf, TemplateFlowError>(local_path);
                        }
                        Err(_e) if attempts < options.max_retries => {
                            // Wait before retry with exponential backoff
                            let delay = std::time::Duration::from_millis(100 * 2u64.pow(attempts));
                            tokio::time::sleep(delay).await;
                            continue;
                        }
                        Err(e) => {
                            if let Some(ref pb) = overall_pb_clone {
                                pb.inc(1);
                            }
                            return Err(e);
                        }
                    }
                }
            }
        })
        .buffer_unordered(options.max_concurrent);

    // Collect all downloads
    let download_results: Vec<Result<PathBuf>> = download_stream.collect().await;

    // Finish overall progress
    if let Some(ref pb) = overall_pb {
        pb.finish_with_message(format!("Downloaded {} files", num_downloads));
    }

    // Collect results
    let mut downloaded_paths = already_cached;
    for result in download_results {
        downloaded_paths.push(result?);
    }

    Ok(downloaded_paths)
}

/// Options for parallel downloads
#[derive(Debug, Clone)]
pub struct ParallelDownloadOptions {
    /// Maximum number of concurrent downloads (default: 5)
    pub max_concurrent: usize,
    /// Maximum number of retry attempts per file (default: 3)
    pub max_retries: u32,
    /// Show progress bars during download (default: true)
    pub show_progress: bool,
}

impl Default for ParallelDownloadOptions {
    fn default() -> Self {
        Self {
            max_concurrent: 5,
            max_retries: 3,
            show_progress: true,
        }
    }
}

