//! Basic usage example for TemplateFlow Rust library
//!
//! This example demonstrates the fundamental operations:
//! - Listing available templates
//! - Querying template files
//! - Downloading template files
//! - Accessing template metadata

use std::collections::HashMap;
use templateflow::{get, ls, templates, get_metadata, get_citations};

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("=== TemplateFlow Basic Usage Example ===\n");

    // 1. List all available templates
    println!("1. Listing all available templates:");
    let all_templates = templates(None)?;
    println!("   Found {} templates", all_templates.len());
    println!("   First 5 templates: {:?}\n", &all_templates[..5.min(all_templates.len())]);

    // 2. Query files for a specific template
    let template_name = "MNI152NLin2009cAsym";
    println!("2. Querying files for template '{}':", template_name);

    // List all files for the template
    let all_files = ls(template_name, None)?;
    println!("   Total files: {}", all_files.len());

    // Query with specific parameters
    let mut query = HashMap::new();
    query.insert("resolution".to_string(), "1".to_string());
    query.insert("suffix".to_string(), "T1w".to_string());

    let t1w_files = ls(template_name, Some(&query))?;
    println!("   T1w files at resolution 1: {:?}\n", t1w_files);

    // 3. Download a template file
    println!("3. Downloading template file:");
    if !t1w_files.is_empty() {
        let local_paths = get(template_name, Some(&query))?;
        if let Some(local_path) = local_paths.first() {
            println!("   Downloaded to: {}", local_path.display());

            // Check if file exists
            if local_path.exists() {
                let metadata = std::fs::metadata(&local_path)?;
                println!("   File size: {} bytes", metadata.len());
            }
        }
    }
    println!();

    // 4. Get template metadata
    println!("4. Template metadata for '{}':", template_name);
    match get_metadata(template_name) {
        Ok(metadata) => {
            println!("   Name: {}", metadata.name);
            if let Some(desc) = &metadata.description {
                println!("   Description: {}", desc);
            }
            if let Some(coord) = &metadata.native_coord_system {
                println!("   Coordinate system: {}", coord);
            }
            println!("   Authors: {} author(s)", metadata.authors.len());
            if let Some(license) = &metadata.license {
                println!("   License: {}", license);
            }
        }
        Err(e) => println!("   Error getting metadata: {}", e),
    }
    println!();

    // 5. Get template citations
    println!("5. Template citations:");
    match get_citations(template_name, false) {
        Ok(citations) => {
            println!("   Found {} citation(s)", citations.len());
            for (i, citation) in citations.iter().enumerate() {
                println!("   [{}] {}", i + 1, citation);
            }
        }
        Err(e) => println!("   Error getting citations: {}", e),
    }
    println!();

    // 6. Query different file types
    println!("6. Querying different file types:");

    // Query brain masks
    let mut mask_query = HashMap::new();
    mask_query.insert("suffix".to_string(), "mask".to_string());
    let masks = ls(template_name, Some(&mask_query))?;
    println!("   Brain masks: {} files", masks.len());

    // Query parcellations
    let mut parc_query = HashMap::new();
    parc_query.insert("atlas".to_string(), "Schaefer2018".to_string());
    let parcellations = ls(template_name, Some(&parc_query))?;
    println!("   Schaefer2018 parcellations: {} files", parcellations.len());

    // Query probabilistic maps
    let mut prob_query = HashMap::new();
    prob_query.insert("label".to_string(), "GM".to_string());
    let prob_maps = ls(template_name, Some(&prob_query))?;
    println!("   Gray matter probability maps: {} files", prob_maps.len());

    println!("\n=== Example completed successfully! ===");

    Ok(())
}

