//! Async usage example for TemplateFlow Rust library
//!
//! This example demonstrates asynchronous operations:
//! - Concurrent file downloads
//! - Parallel template queries
//! - Async/await patterns with TemplateFlow

use std::collections::HashMap;
use templateflow::{get_async, get_multiple_async, get_multiple_async_advanced, ParallelDownloadOptions};
use tokio::time::Instant;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("=== TemplateFlow Async Usage Example ===\n");

    // 1. Basic async download
    println!("1. Basic async download:");
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "T1w".to_string());
    query.insert("res".to_string(), "02".to_string()); // Use 2mm for faster download

    let start = Instant::now();
    match get_async("MNI152NLin2009cAsym", Some(&query)).await {
        Ok(files) => {
            let duration = start.elapsed();
            println!("   Downloaded {} files in {:?}", files.len(), duration);
            for file in &files {
                println!("   - {}", file.display());
            }
        }
        Err(e) => println!("   Error: {}", e),
    }
    println!();

    // 2. Parallel downloads of multiple files
    println!("2. Parallel downloads (multiple files):");
    let mut mask_query = HashMap::new();
    mask_query.insert("suffix".to_string(), "mask".to_string());

    let start = Instant::now();
    match get_multiple_async("MNI152NLin2009cAsym", Some(&mask_query)).await {
        Ok(files) => {
            let duration = start.elapsed();
            println!("   Downloaded {} mask files concurrently in {:?}", files.len(), duration);
            for file in &files {
                if let Ok(metadata) = std::fs::metadata(&file) {
                    println!("   - {} ({} bytes)", file.file_name().unwrap().to_string_lossy(), metadata.len());
                }
            }
        }
        Err(e) => println!("   Error: {}", e),
    }
    println!();

    // 3. Advanced parallel downloads with options
    println!("3. Advanced parallel downloads with progress:");
    let options = ParallelDownloadOptions {
        max_concurrent: 3,
        max_retries: 2,
        show_progress: true,
    };

    let mut atlas_query = HashMap::new();
    atlas_query.insert("atlas".to_string(), "Schaefer2018".to_string());
    atlas_query.insert("res".to_string(), "02".to_string());

    let start = Instant::now();
    match get_multiple_async_advanced("MNI152NLin2009cAsym", Some(&atlas_query), options).await {
        Ok(files) => {
            let duration = start.elapsed();
            println!("   Downloaded {} atlas files with progress in {:?}", files.len(), duration);
        }
        Err(e) => println!("   Error: {}", e),
    }
    println!();

    // 4. Concurrent operations on multiple templates
    println!("4. Concurrent operations on multiple templates:");
    let templates = vec!["MNI152NLin2009cAsym", "MNI152Lin", "fsaverage"];

    let mut tasks = Vec::new();
    for template in templates {
        let template = template.to_string();
        let task = tokio::spawn(async move {
            // Count T1w files for each template
            let mut query = HashMap::new();
            query.insert("suffix".to_string(), "T1w".to_string());

            match templateflow::ls(&template, Some(&query)) {
                Ok(files) => (template, files.len()),
                Err(_) => (template, 0),
            }
        });
        tasks.push(task);
    }

    // Wait for all tasks to complete
    let results = futures::future::join_all(tasks).await;
    for result in results {
        let (template, count) = result?;
        println!("   {}: {} T1w files", template, count);
    }
    println!();

    // 5. Streaming downloads with timeout
    println!("5. Download with timeout and error handling:");

    // Use tokio::time::timeout for download timeout
    let timeout_duration = tokio::time::Duration::from_secs(30);
    let mut small_query = HashMap::new();
    small_query.insert("suffix".to_string(), "dseg".to_string());
    small_query.insert("res".to_string(), "02".to_string());

    match tokio::time::timeout(
        timeout_duration, 
        get_async("MNI152NLin2009cAsym", Some(&small_query))
    ).await {
        Ok(Ok(files)) => {
            println!("   Successfully downloaded {} files within timeout", files.len());
        }
        Ok(Err(e)) => {
            println!("   Download error: {}", e);
        }
        Err(_) => {
            println!("   Download timed out after {:?}", timeout_duration);
        }
    }
    println!();

    // 6. Async batch processing
    println!("6. Async batch processing pattern:");

    // Process multiple templates in batches
    let all_templates = templateflow::templates(None)?;
    let batch_size = 3;

    for (batch_num, batch) in all_templates.chunks(batch_size).enumerate() {
        println!("   Processing batch {} ({} templates):", batch_num + 1, batch.len());

        let mut batch_tasks = Vec::new();
        for template in batch {
            let template = template.clone();
            let task = tokio::spawn(async move {
                // Get total file count for each template
                match templateflow::ls(&template, None) {
                    Ok(files) => {
                        println!("     {}: {} total files", template, files.len());
                        (template, files.len())
                    }
                    Err(_) => {
                        println!("     {}: error listing files", template);
                        (template, 0)
                    }
                }
            });
            batch_tasks.push(task);
        }

        // Process batch concurrently
        let _batch_results = futures::future::join_all(batch_tasks).await;

        // Only process first few batches for demo
        if batch_num >= 2 {
            println!("   ... (stopping after 3 batches for demo)");
            break;
        }
    }
    println!();

    // 7. Error handling patterns
    println!("7. Async error handling patterns:");

    // Try to download from a non-existent template
    match get_async("NonExistentTemplate", None).await {
        Ok(_) => println!("   Unexpected success"),
        Err(e) => println!("   Expected error for non-existent template: {}", e),
    }

    // Try with invalid query
    let mut invalid_query = HashMap::new();
    invalid_query.insert("suffix".to_string(), "NonExistentSuffix".to_string());

    match get_async("MNI152NLin2009cAsym", Some(&invalid_query)).await {
        Ok(files) if files.is_empty() => println!("   No files found for invalid query (expected)"),
        Ok(files) => println!("   Unexpected files found: {}", files.len()),
        Err(e) => println!("   Error for invalid query: {}", e),
    }

    println!("\n=== Async example completed successfully! ===");
    println!("Key patterns demonstrated:");
    println!("  ✓ Basic async/await usage");
    println!("  ✓ Concurrent downloads");
    println!("  ✓ Parallel processing");
    println!("  ✓ Timeout handling");
    println!("  ✓ Batch processing");
    println!("  ✓ Error handling");

    Ok(())
}

