//! CLI integration example for TemplateFlow
//!
//! This example shows how to integrate TemplateFlow into command-line applications
//! and demonstrates various workflow patterns for neuroimaging pipelines.

use std::collections::HashMap;
use std::path::PathBuf;
use clap::{Parser, Subcommand};
use templateflow::{templates, ls, get, get_metadata};

#[derive(Parser)]
#[command(name = "neuro-pipeline")]
#[command(about = "A neuroimaging pipeline using TemplateFlow")]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// List available templates for analysis
    ListTemplates {
        /// Filter by modality (T1w, T2w, etc.)
        #[arg(short, long)]
        modality: Option<String>,

        /// Filter by resolution
        #[arg(short, long)]
        resolution: Option<String>,
    },

    /// Prepare template data for analysis
    PrepareTemplate {
        /// Template name
        template: String,

        /// Required modality
        #[arg(short, long, default_value = "T1w")]
        modality: String,

        /// Required resolution (01 = 1mm, 02 = 2mm)
        #[arg(short, long, default_value = "01")]
        resolution: String,

        /// Also download brain mask
        #[arg(long)]
        with_mask: bool,

        /// Output directory
        #[arg(short, long)]
        output: Option<PathBuf>,
    },

    /// Setup atlas for parcellation
    SetupAtlas {
        /// Template space
        template: String,

        /// Atlas name (e.g., Schaefer2018, AAL)
        atlas: String,

        /// Number of parcels (for Schaefer atlas)
        #[arg(long)]
        parcels: Option<String>,

        /// Output directory
        #[arg(short, long)]
        output: Option<PathBuf>,
    },

    /// Get template metadata and citations
    Info {
        /// Template name
        template: String,

        /// Generate BibTeX citations
        #[arg(long)]
        bibtex: bool,
    },
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let cli = Cli::parse();

    match cli.command {
        Commands::ListTemplates { modality, resolution } => {
            list_templates_command(modality, resolution)?;
        }

        Commands::PrepareTemplate { template, modality, resolution, with_mask, output } => {
            prepare_template_command(template, modality, resolution, with_mask, output)?;
        }

        Commands::SetupAtlas { template, atlas, parcels, output } => {
            setup_atlas_command(template, atlas, parcels, output)?;
        }

        Commands::Info { template, bibtex } => {
            info_command(template, bibtex)?;
        }
    }

    Ok(())
}

fn list_templates_command(modality: Option<String>, resolution: Option<String>) -> Result<(), Box<dyn std::error::Error>> {
    println!("🧠 Discovering available templates...");

    // Build query based on filters
    let mut query = HashMap::new();
    if let Some(mod_filter) = modality {
        query.insert("suffix".to_string(), mod_filter);
    }
    if let Some(res_filter) = resolution {
        query.insert("res".to_string(), format!("{:02}", res_filter.parse::<u32>()?));
    }

    let filtered_templates = if query.is_empty() {
        templates(None)?
    } else {
        templates(Some(&query))?
    };

    println!("Found {} matching templates:", filtered_templates.len());

    for template in &filtered_templates {
        // Get basic info about each template
        let files = ls(template, query.as_ref())?;
        println!("  📁 {} ({} files)", template, files.len());

        // Show what modalities are available
        if query.is_empty() {
            let modalities = get_available_modalities(template)?;
            if !modalities.is_empty() {
                println!("     Modalities: {}", modalities.join(", "));
            }
        }
    }

    Ok(())
}

fn prepare_template_command(
    template: String, 
    modality: String, 
    resolution: String, 
    with_mask: bool,
    output: Option<PathBuf>
) -> Result<(), Box<dyn std::error::Error>> {
    println!("🔧 Preparing template data for analysis...");
    println!("   Template: {}", template);
    println!("   Modality: {}", modality);
    println!("   Resolution: {}mm", resolution);

    // Build query for main image
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), modality.clone());
    query.insert("res".to_string(), format!("{:02}", resolution.parse::<u32>()?));

    // Download main template image
    println!("📥 Downloading {} image...", modality);
    let main_files = get(&template, Some(&query))?;

    if main_files.is_empty() {
        return Err(format!("No {} files found for template {} at resolution {}", 
                          modality, template, resolution).into());
    }

    println!("✓ Downloaded {} files:", main_files.len());
    for file in &main_files {
        println!("   - {}", file.display());

        // Copy to output directory if specified
        if let Some(ref output_dir) = output {
            copy_to_output(file, output_dir)?;
        }
    }

    // Download brain mask if requested
    if with_mask {
        println!("📥 Downloading brain mask...");
        let mut mask_query = HashMap::new();
        mask_query.insert("suffix".to_string(), "mask".to_string());
        mask_query.insert("desc".to_string(), "brain".to_string());
        mask_query.insert("res".to_string(), format!("{:02}", resolution.parse::<u32>()?));

        match get(&template, Some(&mask_query)) {
            Ok(mask_files) => {
                println!("✓ Downloaded {} mask files:", mask_files.len());
                for file in &mask_files {
                    println!("   - {}", file.display());
                    if let Some(ref output_dir) = output {
                        copy_to_output(file, output_dir)?;
                    }
                }
            }
            Err(_) => {
                println!("⚠️  No brain mask found for this template/resolution");
            }
        }
    }

    println!("🎉 Template preparation complete!");
    Ok(())
}

fn setup_atlas_command(
    template: String,
    atlas: String, 
    parcels: Option<String>,
    output: Option<PathBuf>
) -> Result<(), Box<dyn std::error::Error>> {
    println!("🗺️  Setting up atlas for parcellation...");
    println!("   Template: {}", template);
    println!("   Atlas: {}", atlas);

    // Build atlas query
    let mut query = HashMap::new();
    query.insert("atlas".to_string(), atlas.clone());

    // For Schaefer atlas, add parcel count if specified
    if atlas.contains("Schaefer") {
        if let Some(n_parcels) = parcels {
            query.insert("desc".to_string(), format!("{}Parcels", n_parcels));
            println!("   Parcels: {}", n_parcels);
        }
    }

    // Download atlas files
    println!("📥 Downloading atlas files...");
    let atlas_files = get(&template, Some(&query))?;

    if atlas_files.is_empty() {
        println!("❌ No atlas files found matching criteria");

        // Suggest available atlases
        println!("💡 Available atlases for this template:");
        let mut atlas_query = HashMap::new();
        atlas_query.insert("atlas".to_string(), atlas);
        let available = ls(&template, Some(&atlas_query))?;
        for file in available.iter().take(5) {
            println!("   - {}", file.display());
        }

        return Ok(());
    }

    println!("✓ Downloaded {} atlas files:", atlas_files.len());
    for file in &atlas_files {
        println!("   - {}", file.display());
        if let Some(ref output_dir) = output {
            copy_to_output(file, output_dir)?;
        }
    }

    // Also get the corresponding labels file if available
    let mut label_query = HashMap::new();
    label_query.insert("atlas".to_string(), atlas);
    label_query.insert("suffix".to_string(), "dseg".to_string());

    match get(&template, Some(&label_query)) {
        Ok(label_files) => {
            if !label_files.is_empty() {
                println!("✓ Also downloaded {} label files:", label_files.len());
                for file in &label_files {
                    println!("   - {}", file.display());
                    if let Some(ref output_dir) = output {
                        copy_to_output(file, output_dir)?;
                    }
                }
            }
        }
        Err(_) => {} // Labels not required
    }

    println!("🎉 Atlas setup complete!");
    Ok(())
}

fn info_command(template: String, bibtex: bool) -> Result<(), Box<dyn std::error::Error>> {
    println!("ℹ️  Template Information: {}", template);
    println!("{}", "=".repeat(50));

    // Get metadata
    match get_metadata(&template) {
        Ok(metadata) => {
            println!("Name: {}", metadata.name);

            if let Some(description) = &metadata.description {
                println!("Description: {}", description);
            }

            if !metadata.authors.is_empty() {
                println!("Authors: {}", metadata.authors.join(", "));
            }

            if let Some(license) = &metadata.license {
                println!("License: {}", license);
            }

            println!("References: {} citations", metadata.references_and_links.len());
        }
        Err(e) => {
            println!("⚠️  Could not retrieve metadata: {}", e);
        }
    }

    // Show file statistics
    match ls(&template, None) {
        Ok(all_files) => {
            println!("\nFile Statistics:");
            println!("  Total files: {}", all_files.len());

            // Count by modality
            let modalities = get_available_modalities(&template)?;
            for modality in &modalities {
                let mut mod_query = HashMap::new();
                mod_query.insert("suffix".to_string(), modality.clone());
                if let Ok(mod_files) = ls(&template, Some(&mod_query)) {
                    println!("  {} files: {}", modality, mod_files.len());
                }
            }
        }
        Err(e) => {
            println!("⚠️  Could not list files: {}", e);
        }
    }

    // Get citations
    if bibtex {
        println!("\nBibTeX Citations:");
        println!("{}", "-".repeat(50));
        match templateflow::get_citations(&template, true) {
            Ok(citations) => {
                for citation in &citations {
                    println!("{}\n", citation);
                }
            }
            Err(e) => {
                println!("⚠️  Could not retrieve citations: {}", e);
            }
        }
    }

    Ok(())
}

fn get_available_modalities(template: &str) -> Result<Vec<String>, Box<dyn std::error::Error>> {
    let all_files = ls(template, None)?;
    let mut modalities = std::collections::HashSet::new();

    for file in &all_files {
        let filename = file.file_name().unwrap().to_string_lossy();

        // Extract suffix from BIDS filename (everything between last _ and file extension)
        if let Some(suffix_start) = filename.rfind('_') {
            if let Some(suffix_end) = filename.rfind('.') {
                let suffix = &filename[suffix_start + 1..suffix_end];
                // Remove nested extensions like .nii from .nii.gz
                let suffix = suffix.split('.').next().unwrap_or(suffix);
                modalities.insert(suffix.to_string());
            }
        }
    }

    let mut modalities: Vec<String> = modalities.into_iter().collect();
    modalities.sort();
    Ok(modalities)
}

fn copy_to_output(source: &PathBuf, output_dir: &PathBuf) -> Result<(), Box<dyn std::error::Error>> {
    std::fs::create_dir_all(output_dir)?;
    let filename = source.file_name().unwrap();
    let dest = output_dir.join(filename);
    std::fs::copy(source, &dest)?;
    println!("   📤 Copied to: {}", dest.display());
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_cli_parsing() {
        // Test that CLI arguments parse correctly
        let args = vec!["neuro-pipeline", "info", "MNI152NLin2009cAsym"];
        let cli = Cli::try_parse_from(args).unwrap();

        match cli.command {
            Commands::Info { template, bibtex } => {
                assert_eq!(template, "MNI152NLin2009cAsym");
                assert!(!bibtex);
            }
            _ => panic!("Wrong command parsed"),
        }
    }
}

