#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("=== TemplateFlow Advanced Features Example ===\n");

    // 1. Performance benchmarking
    performance_benchmarking().await?;

    // 2. Smart caching strategies
    smart_caching_demo().await?;

    // 3. Bulk template analysis
    bulk_template_analysis().await?;

    // 4. Pipeline integration patterns
    pipeline_integration_demo().await?;

    // 5. Error recovery and resilience
    error_recovery_demo().await?;

    // 6. Custom download strategies
    custom_download_strategies().await?;

    println!("\n=== Advanced features example completed! ===");
    Ok(())
