async fn performance_benchmarking() -> Result<(), Box<dyn std::error::Error>> {
    println!("1. Performance Benchmarking:");
    println!("   Comparing different download strategies...\n");

    let template = "MNI152NLin2009cAsym";
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "mask".to_string());
    query.insert("res".to_string(), "02".to_string());

    // Strategy 1: Sequential downloads
    println!("   📊 Strategy 1: Sequential downloads");
    let start = Instant::now();
    match get(template, Some(&query)) {
        Ok(files) => {
            let sequential_time = start.elapsed();
            println!("      Time: {:?} for {} files", sequential_time, files.len());

            // Strategy 2: Parallel downloads (if we have multiple files)
            if files.len() > 1 {
                println!("   📊 Strategy 2: Parallel downloads");

                // Clear some files to test re-download
                for file in &files[..1.min(files.len())] {
                    let _ = std::fs::remove_file(file);
                }

                let start = Instant::now();
                let parallel_files = get_multiple_async_advanced(
                    template, 
                    Some(&query),
                    ParallelDownloadOptions {
                        max_concurrent: 3,
                        max_retries: 2,
                        show_progress: false, // Disable for cleaner output
                    }
                ).await?;
                let parallel_time = start.elapsed();

                println!("      Time: {:?} for {} files", parallel_time, parallel_files.len());

                if parallel_time < sequential_time {
                    let speedup = sequential_time.as_millis() as f64 / parallel_time.as_millis() as f64;
                    println!("      🚀 Speedup: {:.2}x faster", speedup);
                }
            }
        }
        Err(e) => println!("      Error: {}", e),
    }
    println!();

    Ok(())
}

async fn smart_caching_demo() -> Result<(), Box<dyn std::error::Error>> {
    println!("2. Smart Caching Strategies:");
    println!("   Demonstrating intelligent file management...\n");

    // Cache warmup: Pre-download commonly used files
    println!("   🔥 Cache warmup: Pre-downloading common templates");
    let common_templates = vec!["MNI152NLin2009cAsym", "MNI152Lin"];
    let common_files = vec![
        ("suffix", "T1w"),
        ("suffix", "mask"),
    ];

    for template in &common_templates {
        for (key, value) in &common_files {
            let mut query = HashMap::new();
            query.insert(key.to_string(), value.to_string());
            query.insert("res".to_string(), "02".to_string()); // Use 2mm for faster demo

            match get_async(template, Some(&query)).await {
                Ok(files) => {
                    println!("      ✓ Cached {} {} files for {}", files.len(), value, template);
                }
                Err(_) => {
                    println!("      - No {} files for {}", value, template);
                }
            }
        }
    }

    // Cache hit demonstration
    println!("   💾 Cache hit demonstration:");
    let start = Instant::now();
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "T1w".to_string());
    query.insert("res".to_string(), "02".to_string());

    let cached_files = get("MNI152NLin2009cAsym", Some(&query))?;
    let cache_time = start.elapsed();

    println!("      Retrieved {} files from cache in {:?}", cached_files.len(), cache_time);
    println!("      Cache efficiency: {:.2}ms per file", cache_time.as_millis() as f64 / cached_files.len() as f64);

    println!();
    Ok(())
}

async fn bulk_template_analysis() -> Result<(), Box<dyn std::error::Error>> {
    println!("3. Bulk Template Analysis:");
    println!("   Analyzing all templates for research planning...\n");

    // Get all templates
    let all_templates = templates(None)?;
    println!("   📋 Analyzing {} templates...", all_templates.len());

    // Analyze in parallel batches
    let batch_size = 5;
    let mut analysis_results = Vec::new();

    for (batch_idx, batch) in all_templates.chunks(batch_size).enumerate() {
        println!("   🔍 Processing batch {} ({} templates)", batch_idx + 1, batch.len());

        let mut tasks = Vec::new();
        for template in batch {
            let template = template.clone();
            let task = tokio::spawn(async move {
                analyze_template(&template).await
            });
            tasks.push(task);
        }

        let batch_results = futures::future::join_all(tasks).await;
        for result in batch_results {
            if let Ok(analysis) = result? {
                analysis_results.push(analysis);
            }
        }

        // Only process first few batches for demo
        if batch_idx >= 2 {
            println!("   ... (stopping after 3 batches for demo)");
            break;
        }
    }

    // Summary statistics
    println!("   📊 Analysis Summary:");
    let total_files: usize = analysis_results.iter().map(|a| a.total_files).sum();
    let avg_files = total_files as f64 / analysis_results.len() as f64;

    println!("      Templates analyzed: {}", analysis_results.len());
    println!("      Total files: {}", total_files);
    println!("      Average files per template: {:.1}", avg_files);

    // Find templates with most modalities
    analysis_results.sort_by(|a, b| b.modalities.len().cmp(&a.modalities.len()));
    println!("      Most versatile templates:");
    for result in analysis_results.iter().take(3) {
        println!("        {} ({} modalities: {})", 
                result.name, 
                result.modalities.len(),
                result.modalities.join(", "));
    }

    println!();
    Ok(())
}

async fn pipeline_integration_demo() -> Result<(), Box<dyn std::error::Error>> {
    println!("4. Pipeline Integration Patterns:");
    println!("   Demonstrating neuroimaging workflow integration...\n");

    // Simulation of a preprocessing pipeline
    let template = "MNI152NLin2009cAsym";
    let subject_id = "sub-001";

    println!("   🧠 Preprocessing pipeline for {}", subject_id);

    // Step 1: Get template T1w for registration target
    println!("   1️⃣  Acquiring registration target...");
    let mut t1_query = HashMap::new();
    t1_query.insert("suffix".to_string(), "T1w".to_string());
    t1_query.insert("res".to_string(), "01".to_string());

    let t1_files = get_async(template, Some(&t1_query)).await?;
    if let Some(t1_template) = t1_files.first() {
        println!("      ✓ Template T1w: {}", t1_template.file_name().unwrap().to_string_lossy());
    }

    // Step 2: Get brain mask for skull stripping
    println!("   2️⃣  Acquiring brain mask...");
    let mut mask_query = HashMap::new();
    mask_query.insert("suffix".to_string(), "mask".to_string());
    mask_query.insert("desc".to_string(), "brain".to_string());
    mask_query.insert("res".to_string(), "01".to_string());

    match get_async(template, Some(&mask_query)).await {
        Ok(mask_files) => {
            if let Some(mask) = mask_files.first() {
                println!("      ✓ Brain mask: {}", mask.file_name().unwrap().to_string_lossy());
            }
        }
        Err(_) => {
            println!("      ⚠️  No brain mask available, will generate during preprocessing");
        }
    }

    // Step 3: Get tissue probability maps
    println!("   3️⃣  Acquiring tissue probability maps...");
    let tissues = vec!["GM", "WM", "CSF"];

    for tissue in &tissues {
        let mut tissue_query = HashMap::new();
        tissue_query.insert("suffix".to_string(), "probseg".to_string());
        tissue_query.insert("label".to_string(), tissue.to_string());
        tissue_query.insert("res".to_string(), "01".to_string());

        match get_async(template, Some(&tissue_query)).await {
            Ok(tissue_files) => {
                if !tissue_files.is_empty() {
                    println!("      ✓ {} probability map: {} files", tissue, tissue_files.len());
                }
            }
            Err(_) => {
                println!("      - No {} probability maps found", tissue);
            }
        }
    }

    // Step 4: Setup atlas for functional connectivity
    println!("   4️⃣  Setting up functional connectivity atlas...");
    let mut atlas_query = HashMap::new();
    atlas_query.insert("atlas".to_string(), "Schaefer2018".to_string());
    atlas_query.insert("desc".to_string(), "400Parcels".to_string());

    match get_async(template, Some(&atlas_query)).await {
        Ok(atlas_files) => {
            println!("      ✓ Schaefer 400-parcel atlas: {} files", atlas_files.len());
            for file in &atlas_files {
                if file.to_string_lossy().contains("dseg") {
                    println!("        - Parcellation: {}", file.file_name().unwrap().to_string_lossy());
                } else if file.to_string_lossy().contains("tsv") {
                    println!("        - Label mapping: {}", file.file_name().unwrap().to_string_lossy());
                }
            }
        }
        Err(_) => {
            println!("      ⚠️  Schaefer atlas not available, falling back to AAL");
        }
    }

    println!("   🎉 Pipeline setup complete for {}", subject_id);
    println!();

    Ok(())
}

async fn error_recovery_demo() -> Result<(), Box<dyn std::error::Error>> {
    println!("5. Error Recovery and Resilience:");
    println!("   Demonstrating robust error handling...\n");

    // Test 1: Graceful handling of missing templates
    println!("   🛡️  Test 1: Missing template handling");
    match get_async("NonExistentTemplate2023", None).await {
        Ok(_) => println!("      Unexpected success"),
        Err(e) => println!("      ✓ Gracefully handled missing template: {}", e),
    }

    // Test 2: Fallback strategies
    println!("   🛡️  Test 2: Fallback resolution strategy");
    let template = "MNI152NLin2009cAsym";
    let preferred_resolutions = vec!["01", "02", "2"];

    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "T1w".to_string());

    for res in &preferred_resolutions {
        query.insert("res".to_string(), res.to_string());

        match get_async(template, Some(&query)).await {
            Ok(files) => {
                if !files.is_empty() {
                    println!("      ✓ Found T1w at resolution {}: {} files", res, files.len());
                    break;
                }
            }
            Err(_) => {
                println!("      - Resolution {} not available, trying next...", res);
            }
        }
    }

    // Test 3: Retry with exponential backoff (simulated)
    println!("   🛡️  Test 3: Retry mechanism simulation");
    let max_retries = 3;
    let mut retry_count = 0;

    while retry_count < max_retries {
        retry_count += 1;
        println!("      Attempt {} of {}", retry_count, max_retries);

        // Simulate network operation that might fail
        if retry_count == 2 { // Succeed on second attempt
            println!("      ✓ Operation succeeded after {} retries", retry_count);
            break;
        } else {
            let delay = Duration::from_millis(100 * 2_u64.pow(retry_count));
            println!("      - Failed, waiting {:?} before retry...", delay);
            tokio::time::sleep(delay).await;
        }
    }

    println!();
    Ok(())
}

async fn custom_download_strategies() -> Result<(), Box<dyn std::error::Error>> {
    println!("6. Custom Download Strategies:");
    println!("   Advanced download patterns for different use cases...\n");

    // Strategy 1: Priority-based downloading
    println!("   📋 Strategy 1: Priority-based downloading");
    let template = "MNI152NLin2009cAsym";

    // Define priority order for different file types
    let priority_queries = vec![
        ("High priority: T1w template", vec![("suffix", "T1w"), ("res", "01")]),
        ("Medium priority: Brain mask", vec![("suffix", "mask"), ("desc", "brain")]),
        ("Low priority: Tissue maps", vec![("suffix", "probseg"), ("label", "GM")]),
    ];

    for (description, query_params) in priority_queries {
        println!("      Processing: {}", description);
        let mut query = HashMap::new();
        for (key, value) in query_params {
            query.insert(key.to_string(), value.to_string());
        }

        let start = Instant::now();
        match get_async(template, Some(&query)).await {
            Ok(files) => {
                let duration = start.elapsed();
                println!("        ✓ Downloaded {} files in {:?}", files.len(), duration);
            }
            Err(_) => {
                println!("        - No matching files found");
            }
        }
    }

    // Strategy 2: Selective downloading based on disk space
    println!("   💾 Strategy 2: Disk-space aware downloading");
    let mut size_query = HashMap::new();
    size_query.insert("res".to_string(), "02".to_string()); // Smaller files
    size_query.insert("suffix".to_string(), "T1w".to_string());

    match get_async(template, Some(&size_query)).await {
        Ok(files) => {
            let mut total_size = 0u64;
            for file in &files {
                if let Ok(metadata) = std::fs::metadata(file) {
                    total_size += metadata.len();
                }
            }
            println!("      ✓ Downloaded {} files, total size: {:.2} MB", 
                    files.len(), total_size as f64 / 1_048_576.0);
        }
        Err(e) => {
            println!("      Error: {}", e);
        }
    }

    // Strategy 3: Bandwidth-adaptive downloading
    println!("   🌐 Strategy 3: Bandwidth-adaptive downloading");
    let options = ParallelDownloadOptions {
        max_concurrent: 2, // Conservative for slower connections
        max_retries: 5,    // More retries for unreliable connections
        show_progress: false,
    };

    let mut adaptive_query = HashMap::new();
    adaptive_query.insert("suffix".to_string(), "mask".to_string());
    adaptive_query.insert("res".to_string(), "02".to_string());

    let start = Instant::now();
    match get_multiple_async_advanced(template, Some(&adaptive_query), options).await {
        Ok(files) => {
            let duration = start.elapsed();
            let throughput = files.len() as f64 / duration.as_secs_f64();
            println!("      ✓ Adaptive download: {} files, {:.1} files/sec", files.len(), throughput);
        }
        Err(e) => {
            println!("      Error: {}", e);
        }
    }

    println!();
    Ok(())
}

// Helper structures and functions

#[derive(Debug)]
struct TemplateAnalysis {
    name: String,
    total_files: usize,
    modalities: Vec<String>,
    has_metadata: bool,
}

async fn analyze_template(template: &str) -> Result<TemplateAnalysis, Box<dyn std::error::Error>> {
    // Count total files
    let total_files = match ls(template, None) {
        Ok(files) => files.len(),
        Err(_) => 0,
    };

    // Identify available modalities
    let mut modalities = std::collections::HashSet::new();

    // Check common modalities
    let common_suffixes = vec!["T1w", "T2w", "mask", "probseg", "dseg"];
    for suffix in &common_suffixes {
        let mut query = HashMap::new();
        query.insert("suffix".to_string(), suffix.to_string());

        if let Ok(files) = ls(template, Some(&query)) {
            if !files.is_empty() {
                modalities.insert(suffix.to_string());
            }
        }
    }

    let mut modalities: Vec<String> = modalities.into_iter().collect();
    modalities.sort();

    // Check if metadata is available
    let has_metadata = get_metadata(template).is_ok();

    Ok(TemplateAnalysis {
        name: template.to_string(),
        total_files,
        modalities,
        has_metadata,
    })
}

